import 'package:cloud_firestore/cloud_firestore.dart'; import '../../../../core/constants/firestore_collections.dart'; import '../../../../core/services/firebase/firestore_service.dart'; import '../../domain/entities/review.dart'; import '../../domain/repositories/review_repository.dart';
class ReviewRepositoryImpl implements ReviewRepository{final FirestoreService fs; const ReviewRepositoryImpl(this.fs); CollectionReference<Map<String,dynamic>> get reviews=>fs.collection(FirestoreCollections.reviews); @override Stream<List<Review>> watchSellerReviews({required String sellerId})=>reviews.where('sellerId',isEqualTo:sellerId).where('isHidden',isEqualTo:false).orderBy('createdAt',descending:true).snapshots().map((s)=>s.docs.map((d)=>Review.fromMap(d.id,d.data())).toList()); @override Stream<List<Review>> watchMyReviews({required String reviewerId})=>reviews.where('reviewerId',isEqualTo:reviewerId).orderBy('createdAt',descending:true).snapshots().map((s)=>s.docs.map((d)=>Review.fromMap(d.id,d.data())).toList()); @override Future<Review?> getReview({required String reviewerId,required String productId}) async{final s=await reviews.where('reviewerId',isEqualTo:reviewerId).where('productId',isEqualTo:productId).limit(1).get(); return s.docs.isEmpty?null:Review.fromMap(s.docs.first.id,s.docs.first.data());} @override Future<void> createReview({required String reviewerId,required String sellerId,required String productId,String? chatRoomId,required ReviewRating rating,required String comment}) async{final doc=reviews.doc(); await doc.set({'reviewerId':reviewerId,'sellerId':sellerId,'productId':productId,'chatRoomId':chatRoomId,'rating':rating.value,'comment':comment,'isHidden':false,'isEdited':false,'createdAt':FieldValue.serverTimestamp(),'updatedAt':FieldValue.serverTimestamp()}); await refreshSellerRating(sellerId:sellerId);} @override Future<void> updateReview({required String reviewId,required ReviewRating rating,required String comment}) async{final d=await reviews.doc(reviewId).get(); await reviews.doc(reviewId).update({'rating':rating.value,'comment':comment,'isEdited':true,'updatedAt':FieldValue.serverTimestamp()}); if(d.data()!=null) await refreshSellerRating(sellerId:d.data()!['sellerId'] as String);} @override Future<void> deleteReview({required String reviewId}) async{final d=await reviews.doc(reviewId).get(); await reviews.doc(reviewId).update({'isHidden':true}); if(d.data()!=null) await refreshSellerRating(sellerId:d.data()!['sellerId'] as String);} @override Future<void> refreshSellerRating({required String sellerId}) async{final s=await reviews.where('sellerId',isEqualTo:sellerId).where('isHidden',isEqualTo:false).get(); final list=s.docs.map((d)=>Review.fromMap(d.id,d.data())).toList(); final count=list.length; final avg=count==0?0.0:list.fold<int>(0,(acc,r)=>acc+r.rating.value)/count; await fs.collection(FirestoreCollections.users).doc(sellerId).set({'ratingAverage':double.parse(avg.toStringAsFixed(2)),'reviewCount':count,'trustScore':((avg/5)*100).round(),'updatedAt':FieldValue.serverTimestamp()},SetOptions(merge:true));}}
